parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "productos": {
      "type": "array",
      "description": "Todos los productos encontrados en el texto",
      "items": {
        "type": "object",
        "properties": {
          "marca": { "type": "string", "description": "Marca del producto" },
          "modelo": { "type": "string", "description": "Modelo o nombre del producto" },
          "precio": { "type": "integer", "description": "Precio en CENTAVOS de su moneda original (12999 = 129.99). Multiplica por 100 si el texto da el precio en unidades." },
          "moneda_id": { "type": "integer", "description": "1=MXN (Pesos), 2=USD (Dólares), 3=EUR (Euros). Usa 1 si no se especifica." },
          "stock": { "type": "integer", "description": "Existencias. 0 si no se especifica." },
          "especificaciones": { "type": "object", "description": "Pares clave-valor con caracteristicas tecnicas, p. ej. { \"voltaje\": \"12V\" }. Objeto vacio si no hay." },
          "vehiculos": { "type": "array", "description": "Vehiculos compatibles", "items": { "type": "object", "properties": { "modelo": { "type": "string" }, "marca": { "type": "string" }, "anio": { "type": "integer" } } } },
          "categorias": { "type": "array", "items": { "type": "string" }, "description": "Categorias del producto" },
          "ciudades": { "type": "array", "items": { "type": "string" }, "description": "Ciudades donde esta disponible" }
        },
        "required": ["marca", "modelo", "precio"]
      }
    }
  },
  "required": ["productos"]
}
